
create database superstore;
use superstore;
--- Create Table
CREATE TABLE product_sales (
  Order_ID VARCHAR(20),
  Order_Date DATE,
  Customer_ID VARCHAR(20),
  Customer_Name VARCHAR(100),
  City VARCHAR(100),
  State VARCHAR(100),
  Region VARCHAR(50),
  Category VARCHAR(50),
  Sub_Category VARCHAR(50),
  Product_Name VARCHAR(200),
  Quantity INT,
  Unit_Price DECIMAL(10,2),
  Sales DECIMAL(10,2),
  Profit DECIMAL(10,2)
);

