--- count rows
SELECT COUNT(*) AS total_rows FROM product_sales;

--- 1.Top Products_by revenue ( group by + order by)
--- business problem: which products make most money?

SELECT
  Sub_Category,
  COUNT(*) AS orders,
  SUM(Sales) AS total_revenue,
  ROUND(SUM(Profit)/SUM(Sales)*100, 2) AS profit_margin
FROM product_sales
GROUP BY Sub_Category
ORDER BY total_revenue DESC
LIMIT 10;

--- 2. Regional Performance (group by + having)
--- business problem: which regions perform above 100k revenue?

SELECT
  Region,
  SUM(Sales) AS revenue,
  COUNT(DISTINCT Customer_ID) AS customers,
  AVG(Sales) AS avg_order
FROM product_sales
GROUP BY Region
HAVING SUM(Sales) > 100000
ORDER BY revenue DESC;

--- 3.Customer Lifetime_Value (group by + max)
--- business problem: who are ours most valuable customers ?

SELECT
  Customer_ID,
  COUNT(*) AS order_count,
  SUM(Sales) AS lifetime_value,
  MAX(Order_Date) AS last_order
FROM product_sales
GROUP BY Customer_ID
ORDER BY lifetime_value DESC
LIMIT 10;

--- 4.Monthly Trends(LAG Window function)
--- business problem: is our business growing month by month ?

SELECT
  DATE_FORMAT(Order_Date, '%Y-%m') AS month,
  SUM(Sales) AS monthly_revenue,
  LAG(SUM(Sales)) OVER (ORDER BY DATE_FORMAT(Order_Date, '%Y-%m')) AS prev_month,
  ROUND(
    100.0 * (SUM(Sales) - LAG(SUM(Sales)) OVER (ORDER BY DATE_FORMAT(Order_Date, '%Y-%m')))
    / LAG(SUM(Sales)) OVER (ORDER BY DATE_FORMAT(Order_Date, '%Y-%m')), 2
  ) AS growth_pct
FROM product_sales
GROUP BY DATE_FORMAT(Order_Date, '%Y-%m')
ORDER BY month DESC;
--- 5.Top per category (ROW_NUMBER + CTE)
--- Business problem: What is the hero product in each category ?
 
WITH ranked AS (
  SELECT
    Category,
    Sub_Category,
    SUM(Sales) AS revenue,
    ROW_NUMBER() OVER (PARTITION BY Category ORDER BY SUM(Sales) DESC) AS rnk
  FROM product_sales
  GROUP BY Category, Sub_Category
)
SELECT * FROM ranked WHERE rnk = 1;

--- 6.City wise Sales Ranking (DENSE_RANK WINDOW FUNCTION)
--- Business problem: Which indian city is #1 in sales ?

SELECT
  City,
  State,
  Region,
  SUM(Sales) AS total_sales,
  DENSE_RANK() OVER (ORDER BY SUM(Sales) DESC) AS city_rank
FROM product_sales
GROUP BY City, State, Region
ORDER BY city_rank;

--- 7.Customer Segmentation (RFM) (case when)
--- Business problem: Segment customers into champion, loyal, potential, new

SELECT
  Customer_Name,
  COUNT(*) AS frequency,
  SUM(Sales) AS monetary,
  MAX(Order_Date) AS last_purchase,
  CASE
    WHEN COUNT(*) >= 10 AND SUM(Sales) > 50000 THEN 'Champion'
    WHEN COUNT(*) >= 5  AND SUM(Sales) > 20000 THEN 'Loyal'
    WHEN COUNT(*) >= 3  THEN 'Potential'
    ELSE 'New Customer'
  END AS segment
FROM product_sales
GROUP BY Customer_Name
ORDER BY monetary DESC;

--- 8. Month over Month Growth by Category (LAG + PARTITION BY)
--- Business problem: Which category growing fastest?

SELECT
  Category,
  DATE_FORMAT(Order_Date, '%Y-%m') AS month,
  SUM(Sales) AS monthly_sales,
  LAG(SUM(Sales)) OVER (
    PARTITION BY Category
    ORDER BY DATE_FORMAT(Order_Date, '%Y-%m')
  ) AS prev_month_sales,
  ROUND(
    100.0 * (SUM(Sales) - LAG(SUM(Sales)) OVER (
      PARTITION BY Category
      ORDER BY DATE_FORMAT(Order_Date, '%Y-%m')
    )) / LAG(SUM(Sales)) OVER (
      PARTITION BY Category
      ORDER BY DATE_FORMAT(Order_Date, '%Y-%m')
    ), 2
  ) AS growth_pct
FROM product_sales
GROUP BY Category, DATE_FORMAT(Order_Date, '%Y-%m')
ORDER BY Category, month;

